file_contents.service-config-poc.yaml:
# @mcp-schema: service-config-env
# @mcp-version: 3.0
# @mcp-description: >
#   Per-environment service configuration template for the Everest DevOps Pipeline-as-Code framework.
#   Users copy this file to their ServiceConfig repo as 'service-config-{env}.yaml' (e.g., service-config-dev.yaml)
#   and set environment-specific values such as ARM connections, server names, and resource identifiers.
#   Variables here override or supplement the pipeline-level service-config.yaml for a specific environment.
# @mcp-usage: >
#   1. Copy this file as service-config-dev.yaml, service-config-qa.yaml, service-config-stage.yaml, service-config-prod.yaml, service-config-dr.yaml
#   2. Uncomment and set values specific to each environment
#   3. These variables are loaded during the CD (deploy) stage for the matching environment
#   4. Common pattern: ARM_Service_Connection varies per environment, Deploy_* resources vary per environment
#   5. Only uncomment sections relevant to your Deploy_*_Enabled flags in service-config.yaml
# @mcp-precedence: >
#   Values in this file override values in service-config.yaml for the same key during the matching environment's deployment.
#   Underscore-prefixed variables (_appRoot, _SASTTesting, etc.) are set by the pipeline framework and should NOT be overridden here.
# @mcp-environments: [Dev, QA, Stage, Prod, DR]
# @mcp-relatedFiles:
#   - Service-Config-Template.yaml (pipeline-level config with Deploy_*_Enabled flags and global settings)
#   - PipelineTemplate.yaml (pipeline definition that consumes this config)
#   - CD: templates/main-azure-pipeline.yaml@cdtemplates

variables:
#############################################################################################################################################################
###                                                    SECTION 1: Shared / Cross-Deploy-Type                                                              ###
#############################################################################################################################################################

## @mcp-section { name: "ARM Service Connection", description: "Azure Resource Manager service connection for ARM-based deployments. Used by ADF, Logic Apps, Web Apps, Functions, Terraform, Azure Copy, and others. Also often doubles as the Resource Group name.", scope: "deployType:adf|deployType:webapp|deployType:functions|deployType:logicapp|deployType:terraform|deployType:azcopy" }
    #########################
  ##   ARM Based Deployment  ##
#################################

  ## @mcp { name: "ARM_Service_Connection", type: "string", required: true, description: "Azure DevOps service connection name for ARM deployments. Also typically used as the Resource Group name. Must be configured per environment.", example: "MyApp-Dev-RG", scope: "env" }
  # ARM_Service_Connection: 'MyApp-Dev-RG'

## @mcp-section { name: "Service Actions Targets", description: "Per-environment target server hostnames for Windows service start/stop/restart operations. The service names are set globally in service-config.yaml; the targets vary per environment.", scope: "env" }
    ##################################
  ##     Service Actions Targets      ##
##########################################

  ## @mcp { name: "PreDeploy_Stop_Service_Target", type: "string", required: false, description: "Target server hostname for pre-deploy service stop.", example: "MYSERVER01.domain.net", scope: "env" }
  # PreDeploy_Stop_Service_Target: 'MYSERVER01.domain.net'

  ## @mcp { name: "PreDeploy_Restart_Service_Target", type: "string", required: false, description: "Target server hostname for pre-deploy service restart.", example: "MYSERVER01.domain.net", scope: "env" }
  # PreDeploy_Restart_Service_Target: 'MYSERVER01.domain.net'

  ## @mcp { name: "PostDeploy_Start_Service_Target", type: "string", required: false, description: "Target server hostname for post-deploy service start.", example: "MYSERVER01.domain.net", scope: "env" }
  # PostDeploy_Start_Service_Target: 'MYSERVER01.domain.net'

  ## @mcp { name: "PostDeploy_Restart_Service_Target", type: "string", required: false, description: "Target server hostname for post-deploy service restart.", example: "MYSERVER01.domain.net", scope: "env" }
  # PostDeploy_Restart_Service_Target: 'MYSERVER01.domain.net'

## @mcp-section { name: "Config Updates (Per-Env)", description: "Per-environment KeyVault and secret settings for configuration file updates. Requires Deploy_Config_Updates='true' in service-config.yaml.", scope: "env", relatedTemplate: "config-updates.yaml" }
    ####################################
  ##     Config Updates (Per-Env)      ##
############################################

  ## @mcp { name: "Deploy_Config_Updates_KeyVault", type: "string", required: false, description: "Azure KeyVault name for retrieving deployment secrets in this environment.", example: "ERDevOps-KeyVault", scope: "env" }
  # Deploy_Config_Updates_KeyVault: 'ERDevOps-KeyVault'

  ## @mcp { name: "Deploy_Config_Updates_Subscription", type: "string", required: false, description: "Azure subscription or service connection name for KeyVault access in this environment.", example: "ERDevOps-KeyVault", scope: "env" }
  # Deploy_Config_Updates_Subscription: 'ERDevOps-KeyVault'

  ## @mcp { name: "Deploy_Config_Updates_Secrets", type: "string", required: false, description: "Comma-separated list of KeyVault secret names to retrieve for config updates.", example: "IntegrationCertDev,IntegrationMicrosoftclientid-Dev", scope: "env" }
  # Deploy_Config_Updates_Secrets: 'IntegrationCertDev,IntegrationMicrosoftclientid-Dev'

  ## @mcp { name: "Deploy_Config_Updates_Source", type: "string", required: false, description: "Path to the properties/config file to update with secrets.", example: "$(Pipeline.Workspace)/drop/DEV/Override.properties", scope: "env" }
  # Deploy_Config_Updates_Source: '$(Pipeline.Workspace)/drop/DEV/Override.properties'

  ## @mcp { name: "Deploy_Config_Updates_KeyValues", type: "string", required: false, description: "Key-value mappings for config updates. Format depends on Deploy_Config_Updates_Type in service-config.yaml.", example: "$(@(\"key1=$(SecretName1)\",\"key2=$(SecretName2)\"))", scope: "env" }
  # Deploy_Config_Updates_KeyValues: '$(@("key1=$(SecretName1)","key2=$(SecretName2)"))'

## @mcp-section { name: "File Transform (Per-Env)", description: "Per-environment settings for file transformation during deployment. Requires Deploy_File_Transform_Enabled='true' in service-config.yaml.", scope: "env", relatedTemplate: "file-transform.yaml" }
    ####################################
  ##     File Transform (Per-Env)      ##
############################################

  ## @mcp { name: "Deploy_File_Transform_Overrides", type: "string", required: false, description: "XML/JSON variable substitution overrides for this environment.", example: "-ConnectionStrings.DefaultConnection \"Server=dev-sql;Database=MyDB\"", scope: "env" }
  # Deploy_File_Transform_Overrides: ''

  ## @mcp { name: "Deploy_File_Transform_KeyVault", type: "string", required: false, description: "Primary KeyVault name for file transform secrets.", example: "kv-myapp-dev", scope: "env" }
  # Deploy_File_Transform_KeyVault: ''

  ## @mcp { name: "Deploy_File_Transform_Subscription", type: "string", required: false, description: "Azure subscription/service connection for the primary file transform KeyVault.", example: "MyApp-Dev-RG", scope: "env" }
  # Deploy_File_Transform_Subscription: ''

  ## @mcp { name: "Deploy_File_Transform_Secrets", type: "string", required: false, description: "Comma-separated list of secrets from the primary KeyVault.", example: "db-password,api-key", scope: "env" }
  # Deploy_File_Transform_Secrets: ''

  ## @mcp { name: "Deploy_File_Transform_KeyVault_0", type: "string", required: false, description: "Secondary KeyVault name for additional file transform secrets.", example: "kv-shared-dev", scope: "env" }
  # Deploy_File_Transform_KeyVault_0: ''

  ## @mcp { name: "Deploy_File_Transform_Subscription_0", type: "string", required: false, description: "Azure subscription/service connection for the secondary file transform KeyVault.", example: "SharedServices-Dev-RG", scope: "env" }
  # Deploy_File_Transform_Subscription_0: ''

  ## @mcp { name: "Deploy_File_Transform_Secrets_0", type: "string", required: false, description: "Comma-separated list of secrets from the secondary KeyVault.", example: "shared-cert,shared-key", scope: "env" }
  # Deploy_File_Transform_Secrets_0: ''

  ## @mcp { name: "Deploy_File_Transform_KeyVault_1", type: "string", required: false, description: "Tertiary KeyVault name for additional file transform secrets.", example: "kv-infra-dev", scope: "env" }
  # Deploy_File_Transform_KeyVault_1: ''

  ## @mcp { name: "Deploy_File_Transform_Subscription_1", type: "string", required: false, description: "Azure subscription/service connection for the tertiary file transform KeyVault.", example: "Infra-Dev-RG", scope: "env" }
  # Deploy_File_Transform_Subscription_1: ''

  ## @mcp { name: "Deploy_File_Transform_Secrets_1", type: "string", required: false, description: "Comma-separated list of secrets from the tertiary KeyVault.", example: "infra-cert,infra-token", scope: "env" }
  # Deploy_File_Transform_Secrets_1: ''

## @mcp-section { name: "Replace Tokens (Per-Env)", description: "Per-environment settings for token replacement. Requires Deploy_ReplaceToken_Enabled='true' in service-config.yaml.", scope: "env" }
    ####################################
  ##     Replace Tokens (Per-Env)      ##
############################################

  ## @mcp { name: "Pre_Deploy_Workingdir", type: "string", required: false, description: "Root directory for token replacement file search.", example: "$(System.DefaultWorkingDirectory)", default: "$(System.DefaultWorkingDirectory)", scope: "env" }
  # Pre_Deploy_Workingdir: '$(System.DefaultWorkingDirectory)'

  ## @mcp { name: "Pre_Deploy_ReplaceTokensPath", type: "string", required: false, description: "Glob pattern for files to apply token replacement to.", example: "**/*.config", scope: "env" }
  # Pre_Deploy_ReplaceTokensPath: '**/*.config'

## @mcp-section { name: "Database Backup", description: "Pre-deployment database backup configuration per environment. Requires PreDeploy_DatabaseBackup_Enabled in service-config.yaml.", scope: "env", relatedTemplate: "sql-backup.yaml" }
    #########################
  ##     Database Backup     ##
#################################

  ## @mcp { name: "PreDeploy_DatabaseBackup_Enabled", type: "string", required: false, description: "When 'true', performs a database backup before deployment in this environment.", example: "true", validValues: ["true", "false"], default: "false", scope: "env" }
  # PreDeploy_DatabaseBackup_Enabled: 'true'

  ## @mcp { name: "PreDeploy_DatabaseBackup_Server", type: "string", required: false, description: "SQL Server hostname for the backup.", example: "ENAZGWPCSQLS1.everestre.net", scope: "env" }
  # PreDeploy_DatabaseBackup_Server: 'ENAZGWPCSQLS1.everestre.net'

  ## @mcp { name: "PreDeploy_DatabaseBackup_Databases", type: "string", required: false, description: "Comma-separated database name(s) to back up.", example: "PolicyCenter,ClaimCenter", scope: "env" }
  # PreDeploy_DatabaseBackup_Databases: 'PolicyCenter'

  ## @mcp { name: "PreDeploy_DatabaseBackup_FilePath", type: "string", required: false, description: "Backup file path on the SQL server.", example: "E:\\Backup\\CICD\\", scope: "env" }
  # PreDeploy_DatabaseBackup_FilePath: 'E:\Backup\CICD\'

  ## @mcp { name: "PreDeploy_DatabaseBackup_CopyOnly", type: "string", required: false, description: "When 'true', performs a copy-only backup (no effect on backup chain).", example: "true", validValues: ["true", "false"], default: "true", scope: "env" }
  # PreDeploy_DatabaseBackup_CopyOnly: 'true'

  ## @mcp { name: "PreDeploy_DatabaseBackup_DBCheck", type: "string", required: false, description: "When 'true', runs DBCC CHECKDB before backup.", example: "true", validValues: ["true", "false"], default: "true", scope: "env" }
  # PreDeploy_DatabaseBackup_DBCheck: 'true'

  ## @mcp { name: "PreDeploy_DatabaseBackup_Timeout", type: "string", required: false, description: "Timeout in seconds for the backup operation.", example: "1200", default: "1200", scope: "env" }
  # PreDeploy_DatabaseBackup_Timeout: '1200'

  ## @mcp { name: "PreDeploy_DatabaseBackup_Compress", type: "string", required: false, description: "Backup compression option.", example: "Compress", validValues: ["Compress", "NoCompress"], default: "Compress", scope: "env" }
  # PreDeploy_DatabaseBackup_Compress: 'Compress'

## @mcp-section { name: "Multi Deploy Overrides", description: "Per-environment parallel multi-node deployment configuration. Each line defines variable overrides for one parallel deployment job. Requires Multi_Deploy_Enabled='true' in service-config.yaml.", scope: "env" }
    ###################################
  ##      Multi Deploy Overrides      ##
#########################################

  ## @mcp { name: "Multi_Deploy_Overrides", type: "multiline", required: false, description: "Pipe-delimited list of variable overrides per deployment node. First key=value pair's value becomes the job display name. Each line runs as a separate parallel job.", example: "Node=Server1|Deploy_GWPC_TomCatServer=ENGWPCBTS1.everestre.net", scope: "env" }
  # Multi_Deploy_Overrides: |-
  #   Node=BT1|Deploy_GWPC_TomCatServer=ENGWPCBTS1.everestre.net
  #   Node=BT2|Deploy_GWPC_TomCatServer=ENGWPCBTS2.everestre.net
  #   Node=AP1|Deploy_GWPC_TomCatServer=ENGWPCAPS1.everestre.net
  #   Node=AP2|Deploy_GWPC_TomCatServer=ENGWPCAPS2.everestre.net

#############################################################################################################################################################
###                                                    SECTION 2: Per-Environment Deploy Settings                                                         ###
#############################################################################################################################################################

## @mcp-section { name: "AKS Deploy", description: "Per-environment AKS cluster targeting. Cluster name determines blue/green color and region automatically.", scope: "deployType:aks", relatedTemplate: "aks-deploy.yaml" }
    #########################
  ##           AKS           ##
#################################

  ## @mcp { name: "Deploy_Aks_ClusterName", type: "string", required: true, description: "AKS cluster name for this environment. Region is auto-detected from the name pattern (caas-*-uk-*, caas-*-ind-*, default US). Blue/green color is auto-resolved via color endpoint.", example: "caas-green-dev", scope: "env" }
  # Deploy_Aks_ClusterName: 'caas-green-dev'

  ## @mcp { name: "Deploy_Aks_Namespace", type: "string", required: true, description: "Kubernetes namespace for the Helm release. If empty, defaults to '{environment}-{ApplicationName}'.", example: "dev-myapp", scope: "env" }
  # Deploy_Aks_Namespace: 'dev-myapp'

  ## @mcp { name: "Deploy_Aks_Args", type: "string", required: false, description: "Additional Helm arguments for AKS deployment. Ideal for --set and --set-string overrides per environment.", example: "--set replicaCount=2 --set ingress.host=myapp-dev.everestre.net", scope: "env" }
  # Deploy_Aks_Args: ''

  ## @mcp { name: "Deploy_Aks_Args_KeyVaultSub", type: "string", required: false, description: "Azure subscription containing the Key Vault used for Helm --set argument secret injection.", example: "10a0700e-a76a-462c-a11c-9af0bd677313", scope: "env" }
  # Deploy_Aks_Args_KeyVaultSub: ''

  ## @mcp { name: "Deploy_Aks_Args_KeyVaultName", type: "string", required: false, description: "Key Vault name containing secrets to inject as Helm --set arguments.", example: "kv-myapp-dev", scope: "env" }
  # Deploy_Aks_Args_KeyVaultName: ''

  ## @mcp { name: "Deploy_Aks_Args_KeyVaultSecrets", type: "string", required: false, description: "Comma-delimited list of Key Vault secret names to retrieve and inject as Helm --set arguments.", example: "db-password,api-key,redis-connection", scope: "env" }
  # Deploy_Aks_Args_KeyVaultSecrets: ''

## @mcp-section { name: "ADF Deploy", description: "Per-environment Azure Data Factory deployment settings.", scope: "deployType:adf", relatedTemplate: "adf-deploy.yaml" }
    #########################
  ##           ADF           ##
#################################

  ## @mcp { name: "Deploy_ADF_DevName", type: "string", required: true, description: "Source (development) Data Factory name to replace in ARM template.", example: "erazmyappadfd1", scope: "env" }
  # Deploy_ADF_DevName: 'erazmyappadfd1'

  ## @mcp { name: "Deploy_ADF_Name", type: "string", required: true, description: "Target Data Factory name for this environment.", example: "erazmyappadfq1", scope: "env" }
  # Deploy_ADF_Name: 'erazmyappadfq1'

  ## @mcp { name: "Deploy_ADF_DevIRName", type: "string", required: true, description: "Development Integration Runtime name to replace in ARM template.", example: "myapp-adf-dev-ir", scope: "env" }
  # Deploy_ADF_DevIRName: 'myapp-adf-dev-ir'

  ## @mcp { name: "Deploy_ADF_IRName", type: "string", required: true, description: "Target Integration Runtime name for this environment.", example: "myapp-adf-qa-ir", scope: "env" }
  # Deploy_ADF_IRName: 'myapp-adf-qa-ir'

  ## @mcp { name: "Deploy_ADF_Subscription", type: "string", required: true, description: "Azure subscription GUID for this environment's ADF.", example: "10a0700e-a76a-462c-a11c-9af0bd677313", scope: "env" }
  # Deploy_ADF_Subscription: '10a0700e-a76a-462c-a11c-9af0bd677313'

  ## @mcp { name: "Deploy_ADF_Location", type: "string", required: false, description: "Azure region/location of the target ADF resource group.", example: "East US 2", default: "East US 2", scope: "env" }
  # Deploy_ADF_Location: 'East US 2'

## @mcp-section { name: "ESB Deploy", description: "Per-environment ESB deployment settings including node count.", scope: "deployType:esb", relatedTemplate: "esb-deploy.yaml" }
    #########################
  ##           ESB           ##
#################################

  ## @mcp { name: "Deploy_ESB_Node_Count", type: "string", required: true, description: "Number of ESB deployment nodes for this environment.", example: "3", scope: "env" }
  # Deploy_ESB_Node_Count: '1'

## @mcp-section { name: "Terraform Deploy", description: "Per-environment Terraform state backend and service connection settings.", scope: "deployType:terraform", relatedTemplate: "terraform-deploy.yaml" }
    ##########################
  ##         Terraform        ##
##################################

  ## @mcp { name: "Deploy_TF_AzServiceConnection", type: "string", required: true, description: "Azure DevOps service connection for Terraform provider auth in this environment.", example: "EverestAPIM-Dev-RG", scope: "env" }
  # Deploy_TF_AzServiceConnection: 'EverestAPIM-Dev-RG'

  ## @mcp { name: "Deploy_TF_ResourcegrpName", type: "string", required: false, description: "Azure Resource Group for Terraform state storage.", example: "EverestAPIM-Dev-RG", scope: "env" }
  # Deploy_TF_ResourcegrpName: 'EverestAPIM-Dev-RG'

  ## @mcp { name: "Deploy_TF_StorageActName", type: "string", required: true, description: "Azure Storage Account name for Terraform remote state.", example: "usapimterraformstated1", scope: "env" }
  # Deploy_TF_StorageActName: 'usapimterraformstated1'

  ## @mcp { name: "Deploy_TF_StorageContainerName", type: "string", required: true, description: "Azure Blob container name for Terraform state file.", example: "apidevopsdevstatecontainer", scope: "env" }
  # Deploy_TF_StorageContainerName: 'apidevopsdevstatecontainer'

## @mcp-section { name: "Terragrunt Deploy", description: "Per-environment Terragrunt IaC deployment settings including state backend and multi-region/division targeting.", scope: "deployType:terragrunt", relatedTemplate: "iac-terragrunt-deploy.yaml" }
    #############################
  ##         Terragrunt          ##
#####################################

  ## @mcp { name: "Deploy_TG_AzServiceConnection", type: "string", required: true, description: "Azure DevOps service connection for Terragrunt provider auth.", example: "MyInfra-Dev-RG", scope: "env" }
  # Deploy_TG_AzServiceConnection: 'MyInfra-Dev-RG'

  ## @mcp { name: "Deploy_TG_StateFileSubscriptionId", type: "string", required: true, description: "Azure subscription GUID where Terraform state storage account resides.", example: "10a0700e-a76a-462c-a11c-9af0bd677313", scope: "env" }
  # Deploy_TG_StateFileSubscriptionId: '10a0700e-a76a-462c-a11c-9af0bd677313'

  ## @mcp { name: "Deploy_TG_StateFileRG", type: "string", required: true, description: "Resource Group name containing the state storage account.", example: "rg-terraform-state-dev", scope: "env" }
  # Deploy_TG_StateFileRG: 'rg-terraform-state-dev'

  ## @mcp { name: "Deploy_TG_StateFileName", type: "string", required: true, description: "Terraform state file name in remote backend.", example: "terraform.tfstate", scope: "env" }
  # Deploy_TG_StateFileName: 'terraform.tfstate'

  ## @mcp { name: "Deploy_TG_StorageActName", type: "string", required: true, description: "Azure Storage Account name for Terragrunt remote state.", example: "sttfstatedev01", scope: "env" }
  # Deploy_TG_StorageActName: 'sttfstatedev01'

  ## @mcp { name: "Deploy_TG_StorageContainerName", type: "string", required: true, description: "Azure Blob container name for Terragrunt state file.", example: "tfstate", scope: "env" }
  # Deploy_TG_StorageContainerName: 'tfstate'

  ## @mcp { name: "Deploy_TG_Environment", type: "string", required: true, description: "Terragrunt environment identifier used in folder path resolution.", example: "dev", scope: "env" }
  # Deploy_TG_Environment: 'dev'

  ## @mcp { name: "Deploy_TG_Region", type: "string", required: true, description: "Terragrunt region identifier used in folder path resolution.", example: "eastus2", scope: "env" }
  # Deploy_TG_Region: 'eastus2'

  ## @mcp { name: "Apply_TG_Enabled", type: "string", required: false, description: "When 'true', applies Terragrunt changes (vs. plan-only). Default 'true'.", example: "true", validValues: ["true", "false"], default: "true", scope: "env" }
  # Apply_TG_Enabled: 'true'

## @mcp-section { name: "Web App Deploy", description: "Per-environment Azure Web App deployment settings. Requires Deploy_WebApp_Enabled='true' in service-config.yaml.", scope: "deployType:webapp", relatedTemplate: "azure-app-deploy.yaml" }
    #############################
  ##           Web App           ##
#####################################

  ## @mcp { name: "Deploy_WebApp_Name", type: "string", required: true, description: "Azure App Service name for this environment.", example: "myapp-webapp-dev", scope: "env" }
  # Deploy_WebApp_Name: 'myapp-webapp-dev'

  ## @mcp { name: "Deploy_WebApp_Deploy_PackagePath", type: "string", required: false, description: "Path to the deployment package for this environment.", example: "$(Pipeline.Workspace)/drop/*.zip", default: "$(Pipeline.Workspace)/drop/*.zip", scope: "env" }
  # Deploy_WebApp_Deploy_PackagePath: '$(Pipeline.Workspace)/drop/*.zip'

  ## @mcp { name: "Deploy_WebApp_Type", type: "string", required: false, description: "Azure App Service type.", example: "webAppLinux", validValues: ["webApp", "webAppLinux", "webAppContainer"], default: "webApp", scope: "env" }
  # Deploy_WebApp_Type: 'webApp'

  ## @mcp { name: "Deploy_WebApp_Stack", type: "string", required: false, description: "Runtime stack for Linux web apps.", example: "PYTHON|3.11", scope: "env" }
  # Deploy_WebApp_Stack: ''

  ## @mcp { name: "Deploy_WebApp_Startup", type: "string", required: false, description: "Startup command for the web app.", example: "streamlit run app.py", scope: "env" }
  # Deploy_WebApp_Startup: ''

  ## @mcp { name: "Deploy_WebApp_AppSettings", type: "string", required: false, description: "App settings to set on the Web App. Format: -key1 value1 -key2 value2.", example: "-WEBSITE_NODE_DEFAULT_VERSION 18-lts", scope: "env" }
  # Deploy_WebApp_AppSettings: ''

  ## @mcp { name: "Deploy_WebApp_Configs", type: "string", required: false, description: "Additional configuration settings for the Web App.", example: "-phpVersion off", scope: "env" }
  # Deploy_WebApp_Configs: ''

  ## @mcp { name: "Deploy_WebApp_VirtualApplication", type: "string", required: false, description: "Virtual application path.", example: "/", default: "/", scope: "env" }
  # Deploy_WebApp_VirtualApplication: '/'

  ## @mcp { name: "Deploy_WebApp_Deploy_Type", type: "string", required: false, description: "Deployment method.", example: "zipDeploy", validValues: ["zipDeploy", "webDeploy", "runFromPackage", "war"], default: "zipDeploy", scope: "env" }
  # Deploy_WebApp_Deploy_Type: 'zipDeploy'

  ## @mcp { name: "Deploy_WebApp_UseWebDeploy", type: "string", required: false, description: "When 'true', uses WebDeploy.", example: "false", validValues: ["true", "false"], default: "false", scope: "env" }
  # Deploy_WebApp_UseWebDeploy: 'false'

  ## @mcp { name: "Deploy_WebApp_Restart", type: "string", required: false, description: "When 'true', restarts the web app after deployment.", example: "true", validValues: ["true", "false"], default: "false", scope: "env" }
  # Deploy_WebApp_Restart: 'false'

  ## @mcp { name: "Deploy_WebApp_Script", type: "string", required: false, description: "Post-deployment script type.", example: "Inline Script", validValues: ["Inline Script", "File Path"], scope: "env" }
  # Deploy_WebApp_Script: ''

  ## @mcp { name: "Deploy_WebApp_Inline", type: "string", required: false, description: "Inline script content for post-deployment.", example: "echo 'Deployment complete'", scope: "env" }
  # Deploy_WebApp_Inline: ''

  ## @mcp { name: "Deploy_WebApp_ScriptPath", type: "string", required: false, description: "File path to post-deployment script.", example: "$(Pipeline.Workspace)/drop/deploy.ps1", scope: "env" }
  # Deploy_WebApp_ScriptPath: ''

  ## @mcp { name: "Deploy_WebApp_Docker_Namespace", type: "string", required: false, description: "Docker namespace for container-based Web App deployment.", example: "myacr.azurecr.io", scope: "env" }
  # Deploy_WebApp_Docker_Namespace: ''

  ## @mcp { name: "Deploy_WebApp_Docker_Repo", type: "string", required: false, description: "Docker repository name for container-based Web App deployment.", example: "myapp", scope: "env" }
