file_contents.service-config.yaml:
# @mcp-schema: service-config
# @mcp-version: 3.0
# @mcp-description: >
#   Pipeline-level service configuration template for the Everest DevOps Pipeline-as-Code framework.
#   Users copy this file to their ServiceConfig repo as 'service-config.yaml' and uncomment/configure
#   the variables relevant to their application's build and deploy types.
#   This file defines variables consumed by the CI (build) and CD (deploy) main templates.
#   Variables here apply across ALL environments. For per-environment overrides, use service-config-{env}.yaml.
# @mcp-usage: >
#   1. Copy this file to your ServiceConfig repo root as 'service-config.yaml'
#   2. Set 'Application_BuildType' to your build technology (e.g., 'dotnetcore', 'npm', 'python')
#   3. Uncomment and configure the Build_* variables for that type
#   4. Set 'Deploy_*_Enabled: true' for each deployment target you need
#   5. Set global deploy variables here; per-environment values go in service-config-{env}.yaml
#   6. For multi-technology builds, pipe-delimit types: 'dotnetcore|npm'
#   7. To also build a Docker image, set 'Build_Docker: true' alongside your primary buildType
# @mcp-precedence: >
#   Values in service-config-{env}.yaml override values in service-config.yaml for the same key.
#   Underscore-prefixed variables (_appRoot, _SASTTesting, etc.) are set by the pipeline framework
#   and should NOT be overridden here.
# @mcp-buildTypes: [esb, adf, dotnetcore, dotnetasp, python, npm, gradle, maven, terraform, dacpac, sitecore, powerplatform, gwpc, claimcenter, ccinternational, ircom, logicapp, apic, powerbi, pega, sources, mlops, docker, adb, adb1, dash, port_idp, astro, devops]
# @mcp-deployTypes: [aks, adf, esb, terraform, terragrunt, iis, webapp, functions, dacpac, file, apic, mlops, mlopsmodel, powerbi, powerplatform, gwpc, claimcenter, claimcenterint, ircom, sitecore, cloudrun, dash, python, dotnet_custom, maven, tomcat, adbaction, azcopy, installer, pega, logicapp]
# @mcp-relatedFiles:
#   - Service-Config-Env-Template.yaml (per-environment overrides)
#   - PipelineTemplate.yaml (pipeline definition that consumes this config)
#   - CI: templates/main-azure-pipeline.yaml@citemplates
#   - CD: templates/main-azure-pipeline.yaml@cdtemplates

variables:
#############################################################################################################################################################
###                                                         SECTION 1: Global Configurables                                                               ###
#############################################################################################################################################################
## @mcp-section { name: "Build Naming", description: "Pipeline-wide build naming and versioning. These apply regardless of build or deploy type." }
    ####################################
  ##          Build Naming              ##
############################################

  ## @mcp { name: "Build_SourceDescription", type: "string", required: false, description: "Custom description appended to the build name for traceability. Appears in the pipeline run title.", example: "HotfixRelease_v2", scope: "global" }
  # Build_SourceDescription: 'SomeChangeDescription'

  ## @mcp { name: "Build_SourceVersion", type: "string", required: false, description: "Custom semantic version override for the build. When set, replaces the auto-generated build number.", example: "0.4.5", scope: "global" }
  # Build_SourceVersion: 0.4.5

## @mcp-section { name: "Config Updates", description: "Settings for runtime configuration file updates during deployment (token replacement, KeyVault secret injection). When enabled, runs config-updates.yaml after artifact download.", scope: "global", relatedTemplate: "config-updates.yaml" }
    ####################################
  ##          Config Updates           ##
############################################

  ## @mcp { name: "Deploy_Config_Updates", type: "string", required: false, description: "When 'true', enables configuration file updates during deployment using token replacement or KeyVault secrets.", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  # Deploy_Config_Updates: 'true'

  ## @mcp { name: "Deploy_Config_Updates_Type", type: "string", required: false, description: "Type of configuration update to perform. Determines the parsing engine used by ConfigurationsActions.ps1.", example: "JavaProperties", validValues: ["JavaProperties", "XMLAttribute", "XMLNode", "JSON", "YAML", "StringReplace"], scope: "global" }
  # Deploy_Config_Updates_Type: 'JavaProperties'

## @mcp-section { name: "Replace Tokens", description: "Token replacement in deployment artifacts using the ReplaceTokens task. Tokens in files are replaced with pipeline variable values.", scope: "global" }
    ####################################
  ##          Replace Tokens           ##
############################################

  ## @mcp { name: "Deploy_ReplaceToken_Enabled", type: "string", required: false, description: "When 'true', enables the Replace Tokens pre-deploy step for variable substitution in config files.", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  # Deploy_ReplaceToken_Enabled: 'true'

## @mcp-section { name: "File Transform", description: "File transformation during deployment. Supports XML transforms, JSON variable substitution, and config file overrides.", scope: "global", relatedTemplate: "file-transform.yaml" }
    ####################################
  ##         File Transform            ##
############################################

  ## @mcp { name: "Deploy_File_Transform_Enabled", type: "string", required: false, description: "When 'true', enables file transformation during deployment.", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  # Deploy_File_Transform_Enabled: 'true'

## @mcp-section { name: "Pre/Post Deploy Scripts", description: "Custom PowerShell scripts to run before or after the main deployment. Scripts are sourced from the pipeline repo's SharedScripts folder or defined inline.", scope: "global" }
    ####################################
  ##      Pre/Post Deploy Scripts      ##
############################################

  ## @mcp { name: "Pre_Deploy_Script", type: "string", required: false, description: "When 'true', runs a custom pre-deploy PowerShell script before the deployment steps.", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  # Pre_Deploy_Script: 'true'

  ## @mcp { name: "Pre_Deploy_Script_Args", type: "string", required: false, description: "Arguments passed to the pre-deploy PowerShell script.", example: "-Action Prepare -Verbose", scope: "global" }
  # Pre_Deploy_Script_Args: ''

  ## @mcp { name: "Post_Deploy_Script", type: "string", required: false, description: "When 'true', runs a custom post-deploy PowerShell script after the deployment steps.", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  # Post_Deploy_Script: 'true'

  ## @mcp { name: "Post_Deploy_Script_Args", type: "string", required: false, description: "Arguments passed to the post-deploy PowerShell script.", example: "-Action Verify -Verbose", scope: "global" }
  # Post_Deploy_Script_Args: ''

  ## @mcp { name: "Infra_Post_Deploy_Script", type: "string", required: false, description: "When 'true', runs an infrastructure post-deploy script (e.g., DNS updates, firewall rules).", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  # Infra_Post_Deploy_Script: 'true'

  ## @mcp { name: "Infra_Post_Deploy_Script_Args", type: "string", required: false, description: "Arguments passed to the infrastructure post-deploy script.", example: "-Action ConfigureDNS", scope: "global" }
  # Infra_Post_Deploy_Script_Args: ''

## @mcp-section { name: "Service Actions", description: "Windows service start/stop/restart operations before or after deployment. Each action targets a remote server.", scope: "global", relatedTemplate: "service-actions.yaml" }
    ####################################
  ##         Service Actions           ##
############################################

  ## @mcp { name: "PreDeploy_Stop_Service", type: "string", required: false, description: "Windows service name to STOP before deployment begins.", example: "MyWindowsService", scope: "global" }
  # PreDeploy_Stop_Service: 'MyWindowsService'

  ## @mcp { name: "PreDeploy_Stop_Service_Target", type: "string", required: false, description: "Target server hostname for the pre-deploy service stop.", example: "MYSERVER01.domain.net", scope: "env" }
  # PreDeploy_Stop_Service_Target: 'MYSERVER01.domain.net'

  ## @mcp { name: "PreDeploy_Restart_Service", type: "string", required: false, description: "Windows service name to RESTART before deployment begins.", example: "IISAdmin", scope: "global" }
  # PreDeploy_Restart_Service: 'IISAdmin'

  ## @mcp { name: "PreDeploy_Restart_Service_Target", type: "string", required: false, description: "Target server hostname for the pre-deploy service restart.", example: "MYSERVER01.domain.net", scope: "env" }
  # PreDeploy_Restart_Service_Target: 'MYSERVER01.domain.net'

  ## @mcp { name: "PostDeploy_Start_Service", type: "string", required: false, description: "Windows service name to START after deployment completes.", example: "MyWindowsService", scope: "global" }
  # PostDeploy_Start_Service: 'MyWindowsService'

  ## @mcp { name: "PostDeploy_Start_Service_Target", type: "string", required: false, description: "Target server hostname for the post-deploy service start.", example: "MYSERVER01.domain.net", scope: "env" }
  # PostDeploy_Start_Service_Target: 'MYSERVER01.domain.net'

  ## @mcp { name: "PostDeploy_Restart_Service", type: "string", required: false, description: "Windows service name to RESTART after deployment completes.", example: "W3SVC", scope: "global" }
  # PostDeploy_Restart_Service: 'W3SVC'

  ## @mcp { name: "PostDeploy_Restart_Service_Target", type: "string", required: false, description: "Target server hostname for the post-deploy service restart.", example: "MYSERVER01.domain.net", scope: "env" }
  # PostDeploy_Restart_Service_Target: 'MYSERVER01.domain.net'

## @mcp-section { name: "Multi Deploy", description: "Parallel multi-node deployment. When enabled, the deploy job runs once per node with variable overrides. Per-node config goes in service-config-{env}.yaml.", scope: "global" }
    ####################################
  ##          Multi Deploy             ##
############################################

  ## @mcp { name: "Multi_Deploy_Enabled", type: "string", required: false, description: "When 'true', enables parallel multi-node deployment. Requires Multi_Deploy_Overrides in the environment config.", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  # Multi_Deploy_Enabled: 'true'

## @mcp-section { name: "AKS / Docker / Container", description: "Container and Kubernetes settings used when Build_Docker='true' or Deploy_Aks_Enabled='true'. These are pipeline-level (not per-environment).", scope: "buildType:docker|deployType:aks|deployType:cloudrun" }
    ####################################
  ##       AKS / Docker / Container    ##
############################################

  ## @mcp { name: "ApplicationName", type: "string", required: true, description: "Lowercase application name used as the Docker image name, Kubernetes release name, and cloud run service name. Must be DNS-compatible (a-z, 0-9, hyphens).", example: "basecamphub", scope: "buildType:docker|deployType:aks|deployType:cloudrun" }
  # ApplicationName: 'basecamphub'

  ## @mcp { name: "ContainerRegistryName", type: "string", required: false, description: "Name of the container registry (ACR, JFrog, or GAR). Used for Docker push and AKS/CloudRun pull.", example: "AzContainerRegistryD1", default: "azcontainerregistryprod", scope: "buildType:docker|deployType:aks" }
  # ContainerRegistryName: 'azcontainerregistryprod'

## @mcp-section { name: "Artifactory Publishing", description: "Settings for publishing build artifacts to JFrog Artifactory or Azure Artifacts as packages (npm, NuGet, Maven, pip, etc.).", scope: "global", relatedTemplate: "publish-package.yaml" }
    ############################################
  ##           Artifactory Publishing           ##
####################################################

  ## @mcp { name: "PublishPackage", type: "string", required: false, description: "When 'true', publishes build output as a package to JFrog Artifactory or Azure Artifacts.", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  # PublishPackage: 'true'

  ## @mcp { name: "PublishPackage_Feed", type: "string", required: false, description: "Target feed/repository name for package publishing in JFrog or Azure Artifacts.", example: "Everest-Org-Common-Packages", scope: "global" }
  # PublishPackage_Feed: 'Everest-Org-Common-Packages'

  ## @mcp { name: "PublishPackage_Type", type: "string", required: false, description: "Package manager type for publishing.", example: "npm", validValues: ["npm", "nuget", "maven", "gradle", "pip", "universal"], scope: "global" }
  # PublishPackage_Type: 'npm'

  ## @mcp { name: "PublishPackage_Path", type: "string", required: false, description: "Path to the artifact(s) to publish.", example: "$(Build.ArtifactStagingDirectory)", default: "$(Build.ArtifactStagingDirectory)", scope: "global" }
  # PublishPackage_Path: '$(Build.ArtifactStagingDirectory)'

## @mcp-section { name: "File Copies", description: "Pre-build, post-build, and pre-deploy file copy operations. Format: Source>Destination per line. Destination ending in '/' means folder target; otherwise it renames the file.", scope: "global" }
    ############################################
  ##                File Copies                 ##
####################################################

  ## @mcp { name: "PreBuild_File_Copies", type: "multiline", required: false, description: "Pre-build file copy instructions. Each line: Source>Destination. Supports wildcards (*). Destination ending in '/' copies to folder; otherwise renames.", example: "Source/appsettings.Dev.json>Destination/appsettings.json", scope: "global" }
  #PreBuild_File_Copies: |
  #  Source/File.json>Destination/Ends/In/Frontslash/If/To/Folder/
  #  Source/Folder>Destination/Ends/In/Frontslash/If/To/Folder/
  #  Source/appsettings.Dev.json>Destination/Does/Not/End/In/Frontslash/If/Specifying/Name/appsettings.json
  #  Source/*.json>Destination/Ends/In/Frontslash/If/To/Folder/

  ## @mcp { name: "PostBuild_File_Copies", type: "multiline", required: false, description: "Post-build file copy instructions. Same format as PreBuild_File_Copies. Runs after application build completes.", example: "$(Build.ArtifactStagingDirectory)/config.json>$(Build.ArtifactStagingDirectory)/deploy/", scope: "global" }
  #PostBuild_File_Copies: |
  #  Source/File.json>Destination/Ends/In/Frontslash/If/To/Folder/

  ## @mcp { name: "PreDeploy_File_Copies", type: "multiline", required: false, description: "Pre-deploy file copy instructions. Same format as PreBuild_File_Copies. Runs before application deployment.", example: "Source/web.config>$(Pipeline.Workspace)/drop/web.config", scope: "global" }
  #PreDeploy_File_Copies: |
  #  Source/File.json>Destination/Ends/In/Frontslash/If/To/Folder/

## @mcp-section { name: "Multi Build", description: "Enables building the same solution with multiple configurations in parallel (e.g., per-environment DotNet builds).", scope: "global" }
    ############################################
  ##                Multi Build                 ##
####################################################

  ## @mcp { name: "Multi_Build", type: "string", required: false, description: "When 'true', enables parallel multi-configuration builds. Requires Multi_Build_Configuration.", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  #Multi_Build: 'true'

  ## @mcp { name: "Multi_Build_Parallelism", type: "string", required: false, description: "Maximum number of parallel build jobs for multi-build.", example: "5", default: "5", scope: "global" }
  #Multi_Build_Parallelism: '5'

  ## @mcp { name: "Multi_Build_Configuration", type: "json", required: false, description: "JSON object defining build configurations per environment. Each key is an environment name; its value is an object of build variable overrides.", example: "{\"DEV\":{\"Build_DotNetAsp_Configuration\":\"DEV\"},\"PROD\":{\"Build_DotNetAsp_Configuration\":\"PROD\"}}", scope: "global" }
  #Multi_Build_Configuration: >-
  #  {
  #      "DEV": {
  #          "Build_DotNetAsp_Configuration": "DEV",
  #          "Build_DotNetAsp_Platform": "any cpu"
  #      },
  #      "PROD": {
  #          "Build_DotNetAsp_Configuration": "PROD",
  #          "Build_DotNetAsp_Platform": "any cpu"
  #      }
  #  }

## @mcp-section { name: "ASPM Integration", description: "Application Security Posture Management integration for ArmorCode. Aggregates SAST, SCA, DAST results.", scope: "global" }
    ############################################
  ##          ASPM Integration                  ##
####################################################

  ## @mcp { name: "ASPMIntegration", type: "string", required: false, description: "When 'true', enables ArmorCode ASPM integration to aggregate security scan results.", example: "true", validValues: ["true", "false"], default: "false", scope: "global" }
  # ASPMIntegration: 'true'

#############################################################################################################################################################
###                                                        SECTION 2: Build Configurables                                                                 ###
#############################################################################################################################################################
## @mcp-section { name: "Build Configuration", description: "Set Application_BuildType to ONE of the supported build types, then uncomment and configure the matching Build_* variables below. For multi-technology builds, use pipe-delimited types: 'dotnetcore|npm'." }

## @mcp { name: "Application_BuildType", type: "string", required: true, description: "Primary build technology type. Determines which CI sub-template runs. Use '|' delimiter for multi-technology builds (e.g., 'dotnetcore|npm').", validValues: ["esb", "adf", "dotnetcore", "dotnetasp", "python", "npm", "gradle", "maven", "terraform", "dacpac", "sitecore", "powerplatform", "gwpc", "claimcenter", "ccinternational", "ircom", "logicapp", "apic", "powerbi", "pega", "sources", "mlops", "docker", "adb", "adb1", "dash", "port_idp", "astro", "devops"], example: "dotnetcore", scope: "build" }

## @mcp-section { name: ".NET Core Build", description: "Configuration for .NET Core/6+/8+/9+/10+ application builds using dotnet CLI with JFrog NuGet feeds.", scope: "buildType:dotnetcore", relatedTemplate: "build-dotnet-core-jfrog.yaml" }
    ################################
  ##           DotNetCore           ##
########################################
  # Application_BuildType: 'dotnetcore'

  ## @mcp { name: "Build_DotNetCore_Platform", type: "string", required: false, description: "Target platform for the build.", example: "any cpu", default: "any cpu", scope: "buildType:dotnetcore" }
  # Build_DotNetCore_Platform: 'any cpu'

  ## @mcp { name: "Build_DotNetCore_Projects", type: "multiline", required: true, description: "Glob pattern(s) for .csproj files. Parsed top-to-bottom: includes first, excludes prefixed with !.", example: "**/*.csproj", scope: "buildType:dotnetcore" }
  # Build_DotNetCore_Projects: |
  #   **/*.csproj
  #   !**/tests/**/*.csproj

  ## @mcp { name: "Build_DotNetCore_Configuration", type: "string", required: false, description: "dotnet build configuration.", example: "Release", default: "Release", scope: "buildType:dotnetcore" }
  # Build_DotNetCore_Configuration: 'release'

  ## @mcp { name: "Build_DotNetCore_UseGlobalJson", type: "string", required: false, description: "When 'true', uses global.json to determine .NET SDK version. When 'false', uses Build_DotNetCore_Version.", example: "false", default: "false", validValues: ["true", "false"], scope: "buildType:dotnetcore" }
  # Build_DotNetCore_UseGlobalJson: "false"

  ## @mcp { name: "Build_DotNetCore_Version", type: "string", required: false, description: "Explicit .NET SDK version. Used when Build_DotNetCore_UseGlobalJson is 'false'.", example: "8.0.101", scope: "buildType:dotnetcore" }
  # Build_DotNetCore_Version: "8.0.101"

